INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES
  ('ab100000-e29b-41d4-a716-446655440001', 'hi', 'बोने वाले का दृष्टान्त', 'यीशु ने एक किसान की कहानी सुनाई जो बीज बोता है। बीज अलग-अलग जमीन पर गिरते हैं — कुछ कठोर, कुछ उथले, कुछ काँटों में, और कुछ अच्छी मिट्टी में। यह दृष्टान्त हमसे पूछता है: परमेश्वर के वचन को सुनकर हमारा दिल कैसी मिट्टी है?', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440001', 'ml', 'വിതക്കാരന്റെ ഉപമ', 'യേശു ഒരു കർഷകന്റെ കഥ പറഞ്ഞു — അവൻ വിത്ത് വിതക്കുന്നു, അത് നാല് തരം മണ്ണിൽ വീഴുന്നു. ഓരോ മണ്ണും ദൈവവചനം കേൾക്കുന്ന ഓരോ മനസ്സിനെ കാണിക്കുന്നു. ഈ ഉപമ നമ്മോട് ചോദിക്കുന്നു: നിന്റെ ഹൃദയം ഏത് തരം മണ്ണാണ്?', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440002', 'hi', 'गेहूँ और जंगली घास', 'खेत में गेहूँ और जंगली घास साथ उगती है। मालिक कहता है — कटाई तक इंतजार करो, तभी अलग किया जाएगा। परमेश्वर ही अंत में सच्चे और झूठे शिष्यों को अलग करेगा — यह काम हमारा नहीं।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440002', 'ml', 'ഗോതമ്പും കളയും', 'വയലിൽ ഗോതമ്പിനൊപ്പം കള വളരുന്നു. യജമാനൻ പറയുന്നു — കൊയ്ത്തുവരെ കാത്തിരിക്കൂ. ദൈവം തന്നെ അവസാനം നല്ലതും ചീത്തയും വേർതിരിക്കും. ഇത് നമ്മുടെ ജോലിയല്ല; ദൈവത്തിന്റെ ന്യായവിധി അവനു തന്നെ ഭരമേൽപ്പിക്കാം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440003', 'hi', 'राई के दाने का दृष्टान्त', 'राई का दाना सबसे छोटा होता है, पर बड़ा पेड़ बन जाता है। परमेश्वर का राज्य भी ऐसे ही शुरू हुआ — एक छोटे से गाँव में, कुछ मछुआरों के साथ। लेकिन आज यह सारी दुनिया में फैल गया है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440003', 'ml', 'കടുകുമണിയുടെ ഉപമ', 'കടുകുമണി എല്ലാ വിത്തുകളിലും ഏറ്റവും ചെറുതാണ്, എന്നാൽ അത് വലിയ മരമായി വളരുന്നു. ദൈവരാജ്യവും അങ്ങനെ തന്നെ — ഒരു ചെറിയ തുടക്കത്തിൽ നിന്ന് ലോകമെങ്ങും വ്യാപിക്കുന്നു. ദൈവത്തിന്റെ പ്രവൃത്തി ചെറുതായി കാണപ്പെട്ടാലും അത് ഉറപ്പായി വളരും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440004', 'hi', 'ख़मीर का दृष्टान्त', 'थोड़ा सा ख़मीर पूरे आटे में फैल जाता है। ऐसे ही परमेश्वर का राज्य चुपचाप और धीरे-धीरे सब कुछ बदल देता है। जो छोटा दिखता है, परमेश्वर उसे बड़े काम के लिए इस्तेमाल करता है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440004', 'ml', 'പുളിപ്പിന്റെ ഉപമ', 'കുറച്ച് പുളിപ്പ് മുഴുവൻ മാവിലും ചേർന്ന് പ്രവർത്തിക്കുന്നു. ദൈവരാജ്യവും അങ്ങനെ തന്നെ — ശബ്ദമില്ലാതെ, ഉള്ളിൽ നിന്ന് എല്ലാത്തിനെയും മാറ്റുന്നു. ദൈവം ചെറിയ കാര്യങ്ങൾ ഉപയോഗിച്ച് വലിയ ഫലം ഉണ്ടാക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440005', 'hi', 'खेत में छुपा खज़ाना', 'एक आदमी को खेत में छुपा खज़ाना मिला और उसने अपना सब कुछ बेचकर वह खेत खरीद लिया। परमेश्वर का राज्य ऐसा ही है — जब कोई सच में मसीह को पा लेता है, तो बाकी सब कुछ तुच्छ लगने लगता है। यह बोझ नहीं, आनंद है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440005', 'ml', 'വയലിൽ ഒളിഞ്ഞ നിധി', 'ഒരു മനുഷ്യൻ വയലിൽ ഒളിഞ്ഞ നിധി കണ്ടെത്തി — സന്തോഷത്തോടെ തനിക്കുള്ളതെല്ലാം വിറ്റ് ആ വയൽ വാങ്ങി. ദൈവരാജ്യം ഇങ്ങനെ തന്നെ — ക്രിസ്തുവിനെ ശരിക്കും കണ്ടെത്തുമ്പോൾ, മറ്റെല്ലാം വിടുന്നത് ബുദ്ധിമുട്ടല്ല, ആനന്ദമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440006', 'hi', 'बहुमूल्य मोती', 'एक व्यापारी जीवनभर मोती ढूँढता रहा। जब उसे सबसे कीमती मोती मिला, उसने सब कुछ बेच दिया। मसीह की तुलना में बाकी सब फीका पड़ जाता है — चाहे हम उसे खोजते हों या अचानक पाएँ।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440006', 'ml', 'വിലയേറിയ മുത്ത്', 'ഒരു കച്ചവടക്കാരൻ ജീവിതകാലം മുഴുവൻ നല്ല മുത്തുകൾ തിരഞ്ഞു. ഒടുവിൽ ഏറ്റവും വിലയേറിയ ഒന്ന് കിട്ടിയപ്പോൾ, തനിക്കുള്ളതെല്ലാം വിറ്റ് അത് വാങ്ങി. ക്രിസ്തുവിനോട് താരതമ്യം ചെയ്യുമ്പോൾ മറ്റെല്ലാം വിലകെട്ടതാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440007', 'hi', 'जाल का दृष्टान्त', 'मछुआरे जाल खींचते हैं जिसमें हर तरह की मछलियाँ होती हैं — किनारे पर अच्छी और बुरी अलग की जाती हैं। ऐसे ही युग के अंत में परमेश्वर के दूत धर्मी और अधर्मी को अलग करेंगे। यह न्याय केवल परमेश्वर का है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440007', 'ml', 'വലയുടെ ഉപമ', 'മछുക്കാർ ഒരു വലയിൽ എല്ലാ തരം മത്സ്യങ്ങളെയും പിടിക്കുന്നു — കരയ്ക്ക് വന്നശേഷം നല്ലതും ചീത്തയും വേർതിരിക്കുന്നു. ലോകാവസാനത്തിൽ ദൂതന്മാർ ദൈവഭക്തരെ ദുഷ്ടരിൽ നിന്ന് വേർതിരിക്കും. ഈ ന്യായവിധി ദൈവത്തിന്റേത് മാത്രമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440008', 'hi', 'खोई हुई भेड़', 'एक चरवाहा निन्यानवे भेड़ें छोड़कर एक खोई हुई भेड़ को ढूँढने जाता है। मिलने पर वह खुशी से उसे कंधे पर उठाकर घर लाता है। परमेश्वर हमें खोजता है — हम नहीं खोजते। उद्धार की पहल उसी की है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440008', 'ml', 'കാണാതായ ആടിന്റെ ഉപമ', 'ഒരു ഇടയൻ തൊണ്ണൂറ്റൊമ്പത് ആടുകളെ വിട്ട് കാണാതായ ഒരെണ്ണത്തെ തിരഞ്ഞുപോകുന്നു. കണ്ടെത്തുമ്പോൾ സന്തോഷത്തോടെ തോളിൽ വഹിക്കുന്നു. ദൈവം നമ്മെ തിരഞ്ഞ് വരുന്നു — നമ്മൾ തിരഞ്ഞ് പോകുന്നതല്ല രക്ഷ. ദൈവം തന്നെ ആദ്യം കണ്ടെത്തുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440009', 'hi', 'निर्दयी दास का दृष्टान्त', 'एक दास का बड़ा कर्ज़ माफ कर दिया गया, पर उसने खुद अपने साथी का छोटा कर्ज़ माफ नहीं किया। परमेश्वर ने हमें जितना माफ किया है, उसे समझने वाला दूसरों को भी माफ करेगा। जिसने सच में अनुग्रह पाया है, वह अनुग्रह देगा।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440009', 'ml', 'ക്ഷമിക്കാത്ത ദാസൻ', 'ഒരു ദാസന്റെ വലിയ കടം ക്ഷമിക്കപ്പെട്ടു, എന്നാൽ അവൻ കൂട്ടുദാസന്റെ ചെറിയ കടം ക്ഷമിക്കാൻ തയ്യാറായില്ല. ദൈവം നമ്മെ എത്ര ക്ഷമിച്ചിരിക്കുന്നു എന്ന് ശരിക്കും മനസ്സിലാക്കിയവൻ മറ്റുള്ളവരെ ക്ഷമിക്കും. കൃപ ലഭിച്ചവൻ കൃപ കൊടുക്കും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440010', 'hi', 'अंगूर के बाग के मज़दूर', 'कुछ मज़दूर पूरे दिन काम करते हैं, कुछ सिर्फ एक घंटे — पर सबको एक ही मज़दूरी मिलती है। मालिक की उदारता से पहले वाले नाराज होते हैं। परमेश्वर की कृपा काम या समय से नहीं नापी जाती — यह उसका मुफ्त उपहार है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440010', 'ml', 'മുന്തിരിത്തോട്ടത്തിലെ വേലക്കാർ', 'ചിലർ പകൽ മുഴുവൻ പണിയെടുത്തു, ചിലർ ഒരു മണിക്കൂർ മാത്രം — എന്നാൽ ഉടമ എല്ലാവർക്കും ഒരേ കൂലി കൊടുത്തു. ദൈവത്തിന്റെ കൃപ നാം ചെയ്ത പ്രവൃത്തിയുടെ അളവ് നോക്കി തരുന്നതല്ല. അത് സൗജന്യ ദാനമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440011', 'hi', 'दो बेटों का दृष्टान्त', 'एक बेटे ने "हाँ" कहा पर गया नहीं; दूसरे ने "नहीं" कहा पर पश्चाताप करके गया। यीशु ने कहा: धर्मगुरु मुँह से हाँ करते हैं पर करते नहीं, जबकि पाप करने वाले पश्चाताप करके आगे निकल गए। ज़ुबान से नहीं, जीवन से आज्ञा मानना असली विश्वास है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440011', 'ml', 'രണ്ട് മക്കളുടെ ഉപമ', 'ഒരു മകൻ "ഉവ്വ്" പറഞ്ഞ് പോയില്ല; മറ്റൊരുത്തൻ "ഇല്ല" പറഞ്ഞ് മനസ്സ് മാറി പോയി. വാക്കിൽ "അതെ" എന്ന് പറഞ്ഞ് ജീവിതത്തിൽ ഇല്ല എന്ന് കാണിക്കുന്നത് ശൂന്യമാണ്. യഥാർഥ വിശ്വാസം ജീവിതത്തിൽ അനുസരണമായി കാണപ്പെടും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440012', 'hi', 'दुष्ट किसानों का दृष्टान्त', 'किसानों ने मालिक के दासों को और अंत में उसके बेटे को भी मार डाला। मालिक बाग दूसरों को दे देगा। यह दृष्टान्त उन लोगों की कहानी है जिन्होंने परमेश्वर के पुत्र को ठुकरा दिया — पर राज्य का द्वार अब सबके लिए खुला है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440012', 'ml', 'ദുഷ്ട കൃഷിക്കാരുടെ ഉപമ', 'കൃഷിക്കാർ ഉടമയുടെ ദാസന്മാരെയും ഒടുവിൽ പുത്രനെയും കൊന്നു. ഉടമ മുന്തിരിത്തോട്ടം മറ്റുള്ളവർക്ക് കൊടുക്കും. ദൈവപുത്രനെ തള്ളിക്കളഞ്ഞ ചരിത്രം ഇതിൽ കാണാം — എന്നാൽ രാജ്യത്തിന്റെ വാതിൽ ഇന്ന് എല്ലാവർക്കും തുറന്നിരിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440013', 'hi', 'विवाह भोज का दृष्टान्त', 'बुलाए गए लोगों ने आने से इनकार किया, तो राजा ने सड़कों पर मिले सबको बुलाया। पर बिना सही पोशाक के आए एक व्यक्ति को बाहर निकाल दिया गया। परमेश्वर का निमंत्रण सबके लिए है, पर उसे स्वीकार करना काफी नहीं — उसकी धार्मिकता पहनना ज़रूरी है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440013', 'ml', 'വിവാഹ വിരുന്നിന്റെ ഉപമ', 'ക്ഷണിക്കപ്പെട്ടവർ വരാൻ വിസമ്മതിച്ചു; രാജൻ വഴിയിൽ കണ്ടവരെ ക്ഷണിച്ചു. എന്നാൽ വിവാഹ വസ്ത്രം ധരിക്കാതെ വന്ന ഒരാളെ പുറത്താക്കി. ക്ഷണം കേൾക്കുക മാത്രം പോരാ — ദൈവം നൽകുന്ന നീതി വിശ്വാസത്തിൽ സ്വീകരിക്കണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440014', 'hi', 'दस कुँवारियाँ', 'पाँच कुँवारियाँ तैयार थीं, पाँच नहीं — और जब दूल्हा आया तो अनजान रहने वालों के लिए दरवाज़ा बंद हो गया। "जागते रहो," यीशु ने कहा। असली तैयारी आखिरी वक्त की नहीं, बल्कि मसीह के साथ रोज़ की ज़िंदगी में जीने की है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440014', 'ml', 'പത്ത് കന്യകമാരുടെ ഉപമ', 'അഞ്ച് കന്യകമാർ തയ്യാറായിരുന്നു, അഞ്ചുപേർ ഇല്ലായിരുന്നു — മണവാളൻ വന്നപ്പോൾ തയ്യാറല്ലാത്തവർക്ക് വാതിൽ അടഞ്ഞു. "ജാഗരിക്കുക" എന്ന് യേശു പറഞ്ഞു. ഒടുവിൽ ഓടിക്കൂടുന്ന തയ്യാറെടുപ്പ് പോരാ; ദൈവവുമായുള്ള ദൈനംദിന ബന്ധമാണ് ആവശ്യം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440015', 'hi', 'तालन्तों का दृष्टान्त', 'एक मालिक ने जाने से पहले अपने दासों को अलग-अलग मात्रा में धन सौंपा। दो ने उसे बढ़ाया, एक ने डर के कारण दबा दिया। परमेश्वर ने हमें जो भी दिया है — समय, वरदान, अवसर — उसे ईमानदारी से इस्तेमाल करना ही सच्ची विश्वसनीयता है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440015', 'ml', 'താലന്തുകളുടെ ഉപമ', 'ഒരു യജമാനൻ യാത്ര ചെയ്യും മുമ്പ് ദാസന്മാർക്ക് വ്യത്യസ്ത തുകകൾ ഏൽപ്പിച്ചു. രണ്ടുപേർ അത് ഇരട്ടിയാക്കി; ഒരാൾ ഭയത്തോടെ കുഴിച്ചിട്ടു. ദൈവം നൽകിയ വരങ്ങളും സമയവും ഭീരുതയോടെ ഒളിപ്പിക്കുന്നത് വിശ്വസ്തതക്ക് എതിരാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440016', 'hi', 'भेड़ें और बकरियाँ', 'अंतिम न्याय में परमेश्वर भूखों, प्यासों, अजनबियों और क़ैदियों की देखभाल करने वालों का स्वागत करता है। यह काम उद्धार का आधार नहीं, बल्कि बदले हुए दिल का सबूत है। जिसे मसीह ने बदला, उसकी ज़िंदगी में यह प्यार अपने आप दिखेगा।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440016', 'ml', 'ആടുകളും കോലാടുകളും', 'അന്തിമ ന്യായവിധിയിൽ വിശക്കുന്നവരെ, ദാഹിക്കുന്നവരെ, അപരിചിതരെ, തടവുകാരെ ശ്രദ്ധിച്ചവരെ ദൈവം സ്വീകരിക്കുന്നു. ഈ പ്രവൃത്തികൾ രക്ഷയുടെ അടിസ്ഥാനമല്ല, മറിച്ച് ദൈവം മാറ്റിയ ഹൃദയത്തിന്റെ തെളിവാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440017', 'hi', 'अपने आप बढ़ता बीज', 'एक किसान बीज बोता है, सोता है, जागता है — पर बीज अपने आप बढ़ता रहता है। परमेश्वर का राज्य हमारी कोशिशों से नहीं, उसकी शक्ति से बढ़ता है। हम बोएँ ज़रूर, पर बढ़ाना परमेश्वर का काम है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440017', 'ml', 'സ്വയം വളരുന്ന വിത്ത്', 'ഒരു കർഷകൻ വിത്ത് വിതക്കുന്നു, ഉറങ്ങുന്നു, ഉണരുന്നു — എന്നാൽ വിത്ത് സ്വയം മുളക്കുന്നു. ദൈവരാജ്യം മനുഷ്യന്റെ ശ്രമം കൊണ്ടല്ല, ദൈവത്തിന്റെ ശക്തിയാൽ വളരുന്നു. നാം വിതക്കണം, എന്നാൽ വളർത്തുന്നത് ദൈവം തന്നെ.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440018', 'hi', 'अच्छा सामरी', 'एक आदमी को लुटेरों ने घायल कर छोड़ दिया। याजक और लेवी आगे निकल गए, पर एक सामरी ने रुककर उसकी मदद की। यीशु ने कहा: पड़ोसी वह है जो मदद करता है, न कि जो नज़दीक रहता है। प्यार हर दीवार तोड़ता है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440018', 'ml', 'നല്ല ശമര്യക്കാരൻ', 'ഒരു മനുഷ്യൻ കൊള്ളക്കാരാൽ ആക്രമിക്കപ്പെട്ടു. പുരോഹിതനും ലേവ്യനും കടന്നുപോയി; ഒരു ശമര്യക്കാരൻ മാത്രം നിന്ന് ശ്രദ്ധ നൽകി. "അയൽക്കാരൻ" ആര് എന്ന ചോദ്യം യേശു മാറ്റി — "ആർ അയൽക്കാരനായി ആയി" എന്ന് ചോദിക്കുക. സ്നേഹം അതിർവരമ്പുകൾ ഭേദിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440019', 'hi', 'आधी रात का दोस्त', 'आधी रात को एक दोस्त रोटी माँगने आता है। दोस्त परेशान होकर भी दे देता है। यीशु कहते हैं: अगर एक परेशान इंसान भी देता है, तो हमारा स्वर्गीय पिता तो कितना अधिक देगा! माँगो, और तुम्हें मिलेगा।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440019', 'ml', 'അർദ്ധരാത്രിയിലെ സ്നേഹിതൻ', 'അർദ്ധരാത്രിയിൽ ഒരാൾ അപ്പം ചോദിക്കാൻ സ്നേഹിതന്റെ വീട്ടിൽ വന്നു. ബുദ്ധിമുട്ടോടെ ആണെങ്കിലും സ്നേഹിതൻ കൊടുത്തു. ഒരു മനുഷ്യൻ ഇങ്ങനെ കൊടുക്കുമെങ്കിൽ, നമ്മുടെ സ്വർഗീയ പിതാവ് എത്ര കൂടുതൽ നൽകും! യാചിക്കൂ, ലഭിക്കും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440020', 'hi', 'मूर्ख धनी किसान', 'एक किसान की फसल इतनी अच्छी हुई कि उसने बड़े गोदाम बनाने की सोची — और उस रात वह मर गया। परमेश्वर ने उसे मूर्ख कहा। जीवन धन में नहीं है — दौलत जमा करना और परमेश्वर को भूलना सबसे बड़ी मूर्खता है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440020', 'ml', 'മൂഢനായ ധനവാൻ', 'ഒരു കർഷകന്റെ വിള വളരെ നന്നായി. അവൻ വലിയ കളപ്പുരകൾ പണിയാൻ തീർച്ചയാക്കി — ആ രാത്രിതന്നെ അവൻ മരിച്ചു. ദൈവം അവനെ മൂഢൻ എന്ന് വിളിച്ചു. സ്വത്ത് കൂട്ടി ദൈവത്തെ മറക്കുന്നത് ഏറ്റവും വലിയ ഭോഷത്തമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440021', 'hi', 'फल न देने वाला अंजीर', 'तीन साल से एक अंजीर का पेड़ फल नहीं दे रहा। मालिक काटना चाहता है पर माली एक साल और माँगता है। यह दृष्टान्त दिखाता है कि परमेश्वर धैर्य रखता है — पर यह धैर्य हमेशा के लिए नहीं। फल लाने का वक्त अभी है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440021', 'ml', 'ഫലം കൊടുക്കാത്ത അത്തിമരം', 'മൂന്ന് വർഷമായി ഒരു അത്തിമരം ഫലം കൊടുക്കുന്നില്ല. ഉടമ വെട്ടണം എന്ന് പറഞ്ഞു, തോട്ടക്കാരൻ ഒരു വർഷം കൂടി ചോദിച്ചു. ദൈവം ക്ഷമ കാട്ടുന്നു — എന്നാൽ ആ ക്ഷമക്ക് ഒരു അവസാനം ഉണ്ട്. ഇപ്പോൾ ഫലം കൊടുക്കാൻ നമ്മെ വിളിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440022', 'hi', 'बड़ी दावत का दृष्टान्त', 'एक आदमी ने बड़ी दावत दी पर बुलाए गए सबने बहाने बनाए। तब उसने गलियों में जाकर गरीबों, लंगड़ों और अंधों को बुलाया। जो लोग खुद को व्यस्त समझते हैं, उनके लिए दरवाज़ा बंद हो जाता है। सुसमाचार उनके पास जाता है जो आने को तैयार हैं।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440022', 'ml', 'വലിയ വിരുന്നിന്റെ ഉപമ', 'ഒരാൾ വലിയ വിരുന്ന് ഒരുക്കി, ക്ഷണിക്കപ്പെട്ടവർ ഒഴിവ് പറഞ്ഞു. അപ്പോൾ തെരുവിൽ ഉള്ള ദരിദ്രരെ, അന്ധരെ, മുടന്തരെ ക്ഷണിച്ചു. സ്വയം ആവശ്യമില്ലെന്ന് കരുതുന്നവർ ദൈവരാജ്യം നഷ്ടപ്പെടുത്തുന്നു. സുവിശേഷം ആഗ്രഹിക്കുന്നവരിലേക്ക് ചെല്ലുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440023', 'hi', 'खोए हुए सिक्के का दृष्टान्त', 'एक औरत के दस सिक्कों में से एक खो गया। उसने पूरा घर ढूँढा और मिलने पर पड़ोसनों को बुलाकर ख़ुशी मनाई। खोई भेड़ और उड़ाऊ पुत्र की तरह यह भी कहता है: एक पापी के पश्चाताप पर स्वर्ग में आनंद होता है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440023', 'ml', 'കാണാതായ നാണയം', 'ഒരു സ്ത്രീക്ക് പത്ത് നാണയത്തിൽ ഒന്ന് കാണാതായി. അവൾ വീട് മുഴുവൻ തിരഞ്ഞ് കണ്ടെത്തി, അയൽക്കാരെ ഒരുമിച്ചു ആഘോഷിക്കാൻ വിളിച്ചു. കാണാതായ ആടിന്റെയും ഉടഞ്ഞ മകന്റെയും ഉപമ പോലെ ഇതും പറയുന്നു: ഒരു പാപി മനസ്സ് തിരിഞ്ഞാൽ സ്വർഗ്ഗത്തിൽ ആഘോഷം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440024', 'hi', 'उड़ाऊ पुत्र का दृष्टान्त', 'बेटे ने पिता से हिस्सा माँगा, सब उड़ा दिया, और टूटकर घर लौटा। पिता दूर से ही दौड़कर उसे गले लगाया। यह दृष्टान्त सुसमाचार का सार है — हमारी भटकन, हमारा लौटना, और पिता का असीम प्यार। पर बड़े बेटे की ईर्ष्या भी याद दिलाती है: धर्म का घमंड भी हमें पिता से दूर कर सकता है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440024', 'ml', 'ധൂർത്ത പുത്രന്റെ ഉപമ', 'മകൻ സ്വത്ത് ചോദിച്ചുവാങ്ങി, ധൂർത്തടിച്ചു, ഒടുവിൽ തകർന്ന് വീട്ടിലേക്ക് മടങ്ങി. അപ്പൻ ദൂരെ കാണുമ്പോൾ തന്നെ ഓടിവന്ന് ആലിംഗനം ചെയ്തു. ഈ ഉപമ സുവിശേഷത്തിന്റെ ചുരുക്കം — നമ്മുടെ അലഞ്ഞ് തിരിച്ചടവ്, പിതാവിന്റെ കൃപ. മൂത്ത മകന്റെ അസൂയ ഓർമ്മപ്പെടുത്തുന്നു: ആത്മനീതിയും നമ്മെ പിതാവിൽ നിന്ന് അകറ്റും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440025', 'hi', 'चालाक मुनीम का दृष्टान्त', 'नौकरी जाने वाला एक मुनीम कर्ज़दारों के बिल कम करके अपना भविष्य बना लेता है। यीशु उसकी बेईमानी की नहीं, उसकी चतुराई की तारीफ करते हैं। जो समय हमारे पास है, उसमें परमेश्वर के दिए साधनों को राज्य के लिए समझदारी से लगाएँ।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440025', 'ml', 'സൂക്ഷ്മബുദ്ധിയുള്ള ഗൃഹവിചാരകൻ', 'ജോലി നഷ്ടപ്പെടാൻ പോകുന്ന ഒരു ഗൃഹവിചാരകൻ കടക്കാരുടെ ബില്ലുകൾ കുറച്ച് ഭാവി ഒരുക്കുന്നു. യേശു അവന്റെ ചതിയല്ല, ബുദ്ധി അഭിനന്ദിക്കുന്നു. ദൈവം നൽകിയ സമ്പത്തും സമയവും രാജ്യകാര്യങ്ങൾക്ക് ബുദ്ധിമുട്ടോടെ ഉപയോഗിക്കണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440026', 'hi', 'धनी मनुष्य और लाज़र', 'एक अमीर आदमी हर रोज़ ऐश करता था, और उसके दरवाज़े पर लाज़र भूखा पड़ा रहता था। मरने के बाद दोनों की स्थिति बदल गई। यह दृष्टान्त तीन बातें सिखाता है: मृत्यु के बाद होश रहता है, सांसारिक स्थितियाँ पलट जाती हैं, और परमेश्वर का वचन काफी है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440026', 'ml', 'ധനവാനും ലാസറും', 'ഒരു ധനവാൻ ദിവസവും സുഖിച്ചു; ലാസർ പട്ടിണിയോടെ അവന്റെ വാതിൽക്കൽ കിടന്നു. മരണശേഷം ഇരുവരുടെ സ്ഥിതി മാറി. ഈ ഉപമ മൂന്ന് കാര്യം പഠിപ്പിക്കുന്നു: മരണശേഷം ബോധം ഉണ്ട്, ഐഹിക അവസ്ഥ മാറ്റപ്പെടും, ദൈവവചനം ആവശ്യത്തിന് മതിയാകും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440027', 'hi', 'न्याय माँगने वाली विधवा', 'एक विधवा बार-बार न्यायाधीश के पास जाती है जब तक वह उसकी बात न सुने। यीशु कहते हैं: अगर एक बेईमान न्यायाधीश भी अंत में सुनता है, तो परमेश्वर अपने लोगों की प्रार्थना ज़रूर सुनेगा। हार मानो मत — लगातार माँगते रहो।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440027', 'ml', 'നിരന്തരം ചോദിക്കുന്ന വിധവ', 'ഒരു വിധവ ന്യായാധിപന്റെ അടുക്കൽ തുടർച്ചയായി ന്യായം ചോദിക്കുന്നു; ഒടുവിൽ അവൻ ശ്രദ്ധ കൊടുത്തു. ഒരു അനീതിക്കാരൻ ഇങ്ങനെ ശ്രദ്ധിക്കുമെങ്കിൽ, ദൈവം അവന്റെ ജനത്തിന്റെ യാചന കേൾക്കില്ലേ? തളരാതെ, വിശ്വാസത്തോടെ പ്രാർഥിക്കൂ.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab100000-e29b-41d4-a716-446655440028', 'hi', 'फरीसी और महसूल लेने वाला', 'दोनों मंदिर में प्रार्थना करते हैं। फरीसी अपनी भक्ति गिनाता है; महसूल लेने वाला बस कहता है, "हे परमेश्वर, मुझ पापी पर दया कर।" यीशु कहते हैं: वही घर गया जो परमेश्वर की नज़र में सही ठहरा। नम्रता से माँगना, गर्व से गिनाना नहीं — यही सच्ची प्रार्थना है।', 'विश्वास की नींव'),
  ('ab100000-e29b-41d4-a716-446655440028', 'ml', 'പരീശനും ചുങ്കക്കാരനും', 'രണ്ടുപേർ ദൈവാലയത്തിൽ പ്രാർഥിക്കുന്നു. പരീശൻ തന്റെ നന്മകൾ എണ്ണുന്നു; ചുങ്കക്കാരൻ "ദൈവമേ, എന്നോട് കൃപ ഉണ്ടാകേണമേ" എന്ന് മാത്രം പറയുന്നു. ദൈവം നീതികരിച്ചത് ചുങ്കക്കാരനെ. ആത്മനീതിയിലല്ല, ദൈവകൃപയിൽ ആശ്രയിക്കുന്നവൻ ദൈവ ദൃഷ്ടിയിൽ നീതീകരിക്കപ്പെടുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ')
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES
  ('ab200000-e29b-41d4-a716-446655440001', 'hi', 'धन्य वचन', 'यीशु ने पहाड़ी उपदेश में धन्य लोगों का वर्णन किया। ये वचन बताते हैं कि परमेश्वर के राज्य में कौन सुखी है। नम्र, दयालु और शांति बनाने वाले लोग परमेश्वर के प्रिय हैं।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440001', 'ml', 'ഭാഗ്യവചനങ്ങൾ', 'യേശു മലയിൽ ഇരുന്ന് ഭാഗ്യം ലഭിക്കുന്നവരെ കുറിച്ച് പഠിപ്പിച്ചു. വിനയമുള്ളവർ, ദയയുള്ളവർ, സമാധാനം ഉണ്ടാക്കുന്നവർ എന്നിവർ ദൈവ രാജ്യത്തിൽ അനുഗ്രഹിക്കപ്പെടും. ഈ വചനങ്ങൾ ദൈവ രാജ്യത്തിലെ ജീവിതരീതി കാണിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440002', 'hi', 'नमक और ज्योति', 'यीशु ने अपने शिष्यों को दुनिया का नमक और ज्योति कहा। जैसे नमक भोजन को स्वाद देता है, वैसे ही विश्वासी जीवन को अर्थ देते हैं। हमारे अच्छे कार्य दूसरों को परमेश्वर की महिमा करने के लिए प्रेरित करते हैं।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440002', 'ml', 'ഉപ്പും വെളിച്ചവും', 'യേശു തന്റെ ശിഷ്യന്മാരെ ലോകത്തിന്റെ ഉപ്പും വെളിച്ചവും എന്നു വിളിച്ചു. ഉപ്പ് ആഹാരത്തിന് രുചി നൽകുന്നതുപോലെ, വിശ്വാസികൾ ലോകത്തിന് നന്മ പകരണം. നമ്മുടെ നല്ല പ്രവൃത്തികൾ മറ്റുള്ളവരെ ദൈവത്തെ മഹത്വപ്പെടുത്താൻ നയിക്കും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440003', 'hi', 'मसीह और व्यवस्था', 'यीशु व्यवस्था को नष्ट करने नहीं, बल्कि उसे पूरा करने आए। परमेश्वर का वचन कभी नहीं बदलता और हमेशा सत्य रहता है। यीशु ने व्यवस्था की सच्ची भावना को प्रकट किया और हमें उसके अनुसार जीना सिखाया।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440003', 'ml', 'ക്രിസ്തുവും ന്യായപ്രമാണവും', 'യേശു ന്യായപ്രമാണം നശിപ്പിക്കാനല്ല, പൂർത്തിയാക്കാനാണ് വന്നത്. ദൈവവചനം ഒരിക്കലും മാറില്ല, എന്നും സത്യമായി നിലനിൽക്കും. ന്യായപ്രമാണത്തിന്റെ യഥാർഥ ഉദ്ദേശ്യം യേശു നമ്മെ പഠിപ്പിച്ചു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440004', 'hi', 'क्रोध और मेल-मिलाप', 'यीशु ने सिखाया कि क्रोध भी हत्या जितना गंभीर पाप हो सकता है। परमेश्वर चाहता है कि हम अपने भाइयों से मेल-मिलाप करें। पूजा करने से पहले रिश्तों को ठीक करना जरूरी है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440004', 'ml', 'കോപവും അനുരഞ്ജനവും', 'യേശു പഠിപ്പിച്ചു, കോപം കൊലപാതകം പോലെ തന്നെ ഗുരുതരമായ പാപമാണ്. ദൈവം നമ്മോടു ആഗ്രഹിക്കുന്നത് നാം സഹോദരങ്ങളുമായി അനുരഞ്ജനപ്പെടണം എന്നാണ്. ആരാധിക്കുന്നതിനു മുൻപ് ബന്ധങ്ങൾ ശരിയാക്കുക.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440005', 'hi', 'मन की शुद्धता', 'यीशु ने सिखाया कि बुरी दृष्टि से देखना भी पाप है। पाप केवल बाहरी कार्य नहीं, बल्कि मन के विचारों में भी होता है। परमेश्वर हमारे दिल को देखता है और हमें शुद्ध मन से जीना चाहिए।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440005', 'ml', 'ഹൃദയ ശുദ്ധി', 'ദുഷ്ടമായ ദൃഷ്ടിയോടെ നോക്കുന്നതും പാപമാണെന്ന് യേശു പഠിപ്പിച്ചു. പാപം കേവലം ബാഹ്യ പ്രവൃത്തിയിൽ മാത്രമല്ല, മനസ്സിലെ ചിന്തകളിലും ഉണ്ടാകും. ദൈവം നമ്മുടെ ഹൃദയം കാണുന്നു, അതിനാൽ ശുദ്ധമായ മനസ്സോടെ ജീവിക്കണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440006', 'hi', 'विवाह और तलाक', 'यीशु ने विवाह को परमेश्वर द्वारा बनाया गया पवित्र बंधन बताया। तलाक गंभीर विषय है और परमेश्वर विवाह को महत्व देता है। यीशु ने सिखाया कि हम वैवाहिक वचनों को निष्ठा से निभाएं।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440006', 'ml', 'വിവാഹവും വിവാഹമോചനവും', 'ദൈവം സ്ഥാപിച്ച പുണ്യബന്ധമാണ് വിവാഹമെന്ന് യേശു പഠിപ്പിച്ചു. വിവാഹമോചനം ഗൗരവമുള്ള വിഷയമാണ്, ദൈവം വിവാഹ ബന്ധത്തെ വിലമതിക്കുന്നു. വൈവാഹിക വാഗ്ദത്തങ്ങൾ വിശ്വസ്തതയോടെ പാലിക്കണമെന്ന് യേശു നമ്മെ പഠിപ്പിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440007', 'hi', 'प्रतिज्ञा और ईमानदारी', 'यीशु ने सिखाया कि हमें झूठी कसमें नहीं खानी चाहिए। हमारी बात में "हां" का मतलब हां और "नहीं" का मतलब नहीं होना चाहिए। ईमानदारी और सच्चाई एक मसीही की पहचान है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440007', 'ml', 'സത്യവും സത്യസന്ധതയും', 'കള്ളസ്സത്യം ചെയ്യരുതെന്ന് യേശു പഠിപ്പിച്ചു. നമ്മുടെ ഉവ്വ് ഉവ്വ് ആകണം, ഇല്ല ഇല്ല ആകണം. സത്യസന്ധതയും നേർമ്മയും ഒരു ക്രിസ്ത്യാനിയുടെ അടയാളമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440008', 'hi', 'प्रतिरोध न करना', 'यीशु ने सिखाया कि बुराई का बदला बुराई से न लो। परमेश्वर के राज्य में हम दूसरे गाल को भी आगे करते हैं। यह कमजोरी नहीं, बल्कि परमेश्वर की शक्ति से मिली शांति है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440008', 'ml', 'ചെറുക്കാതിരിക്കൽ', 'തിന്മയ്ക്ക് തിന്മ കൊണ്ട് പകരം ചെയ്യരുതെന്ന് യേശു പഠിപ്പിച്ചു. ദൈവ രാജ്യത്തിൽ നാം മറ്റ് കവിളും തിരിച്ചു കൊടുക്കുന്നു. ഇത് ദൗർബ്ബല്യമല്ല, ദൈവ ശക്തിയിൽ നിന്നുള്ള സമാധാനമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440009', 'hi', 'शत्रुओं से प्रेम', 'यीशु ने हमें अपने दुश्मनों से भी प्यार करने की शिक्षा दी। परमेश्वर अच्छे और बुरे दोनों लोगों पर वर्षा करता है। जब हम अपने शत्रुओं के लिए प्रार्थना करते हैं, तब हम परमेश्वर की संतान बनते हैं।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440009', 'ml', 'ശത്രുക്കളെ സ്നേഹിക്കൽ', 'ശത്രുക്കളെ സ്നേഹിക്കാനും അവർക്കുവേണ്ടി പ്രാർഥിക്കാനും യേശു നമ്മെ പഠിപ്പിച്ചു. ദൈവം നല്ലവർക്കും ദുഷ്ടർക്കും ഒരുപോലെ മഴ നൽകുന്നു. ശത്രുക്കൾക്കുവേണ്ടി പ്രാർഥിക്കുമ്പോൾ നാം ദൈവ മക്കളാകുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440010', 'hi', 'छुपकर दान देना', 'यीशु ने सिखाया कि दान देना दूसरों को दिखाने के लिए नहीं होना चाहिए। परमेश्वर हमारे छुपे हुए कामों को देखता है और उनका प्रतिफल देता है। सच्चा दान वह है जो प्रेम से और बिना दिखावे के किया जाए।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440010', 'ml', 'രഹസ്യത്തിൽ ദാനം ചെയ്യൽ', 'മറ്റുള്ളവരെ കാണിക്കാൻ വേണ്ടി ദാനം ചെയ്യരുതെന്ന് യേശു പഠിപ്പിച്ചു. നമ്മുടെ രഹസ്യ പ്രവൃത്തികൾ ദൈവം കാണുകയും പ്രതിഫലം നൽകുകയും ചെയ്യും. സ്നേഹത്തോടെ, ആഡംബരം കൂടാതെ ചെയ്യുന്ന ദാനമാണ് യഥാർഥ ദാനം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440011', 'hi', 'प्रभु की प्रार्थना', 'यीशु ने अपने शिष्यों को प्रार्थना करने का तरीका सिखाया। इस प्रार्थना में परमेश्वर की महिमा, हमारी जरूरतें और क्षमा माँगना शामिल है। यह प्रार्थना हमें सिखाती है कि परमेश्वर से कैसे बात करें।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440011', 'ml', 'കർത്താവിന്റെ പ്രാർഥന', 'ശിഷ്യന്മാർക്ക് പ്രാർഥിക്കാൻ യേശു ഒരു മാതൃക നൽകി. ഈ പ്രാർഥനയിൽ ദൈവ മഹത്വം, നമ്മുടെ ആവശ്യങ്ങൾ, ക്ഷമ ചോദിക്കൽ എന്നിവ ഉൾപ്പെടുന്നു. ദൈവവുമായി എങ്ങനെ സംസാരിക്കണം എന്ന് ഈ പ്രാർഥന നമ്മെ പഠിപ്പിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440012', 'hi', 'उपवास का महत्व', 'यीशु ने सिखाया कि उपवास दूसरों को दिखाने के लिए नहीं होना चाहिए। परमेश्वर के सामने विनम्रता से किया गया उपवास उसे प्रसन्न करता है। उपवास हमारे मन को परमेश्वर की ओर केंद्रित करने में मदद करता है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440012', 'ml', 'ഉപവാസം', 'ഉപവാസം മറ്റുള്ളവരെ കാണിക്കാൻ ചെയ്യരുതെന്ന് യേശു പഠിപ്പിച്ചു. ദൈവ സന്നിധിയിൽ താഴ്മയോടെ ചെയ്യുന്ന ഉപവാസം അവനെ സന്തോഷിപ്പിക്കുന്നു. നമ്മുടെ ഹൃദയം ദൈവത്തിലേക്ക് തിരിക്കാൻ ഉപവാസം സഹായിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440013', 'hi', 'स्वर्ग में खजाना', 'यीशु ने सिखाया कि इस दुनिया की संपत्ति नाशवान है। हमें स्वर्ग में खजाना इकट्ठा करना चाहिए जो कभी नष्ट नहीं होगा। हमारा दिल जहाँ हमारा खजाना है, वहीं लगा रहता है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440013', 'ml', 'സ്വർഗ്ഗത്തിലെ നിക്ഷേപം', 'ഈ ലോകത്തിലെ സമ്പത്ത് നശ്വരമാണെന്ന് യേശു പഠിപ്പിച്ചു. ഒരിക്കലും നഷ്ടമാകാത്ത സ്വർഗ്ഗത്തിലെ നിക്ഷേപം ശേഖരിക്കണം. നമ്മുടെ നിക്ഷേപം ഉള്ളിടത്ത് നമ്മുടെ ഹൃദയവും ഉണ്ടായിരിക്കും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440014', 'hi', 'चिंता मत करो', 'यीशु ने कहा कि भोजन और वस्त्र के लिए चिंता करने की जरूरत नहीं। परमेश्वर पक्षियों और फूलों का ध्यान रखता है, तो वह हमारा भी ध्यान रखेगा। पहले परमेश्वर के राज्य को खोजो और बाकी सब मिल जाएगा।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440014', 'ml', 'ചിന്തിക്കേണ്ട', 'ഭക്ഷണത്തിനും വസ്ത്രത്തിനും വേണ്ടി ചിന്തിക്കേണ്ടതില്ലെന്ന് യേശു പറഞ്ഞു. പക്ഷികളെയും പൂക്കളെയും ദൈവം പരിപാലിക്കുന്നു, നമ്മെയും അവൻ പോറ്റും. ആദ്യം ദൈവ രാജ്യം തേടൂ, ബാക്കിയെല്ലാം ലഭിക്കും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440015', 'hi', 'दोष मत लगाओ', 'यीशु ने सिखाया कि दूसरों को दोष देने से पहले अपने आप को देखो। पहले अपनी आँख से लकड़ी निकालो, फिर दूसरे की आँख का तिनका हटाओ। दूसरों का न्याय करने का अधिकार केवल परमेश्वर को है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440015', 'ml', 'വിധിക്കരുത്', 'മറ്റുള്ളവരെ കുറ്റം പറയുന്നതിനു മുൻപ് സ്വയം പരിശോധിക്കണമെന്ന് യേശു പഠിപ്പിച്ചു. ആദ്യം സ്വന്തം കണ്ണിലെ തടി നീക്കൂ, പിന്നെ അപരന്റെ കണ്ണിലെ കരട് നീക്കൂ. മറ്റുള്ളവരെ വിധിക്കാനുള്ള അധികാരം ദൈവത്തിന് മാത്രമേ ഉള്ളൂ.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440016', 'hi', 'माँगो, खोजो, खटखटाओ', 'यीशु ने कहा कि परमेश्वर से माँगने पर मिलता है, खोजने पर पाया जाता है। जो खटखटाता है उसके लिए द्वार खोला जाता है। परमेश्वर अपने बच्चों को अच्छी चीजें देना चाहता है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440016', 'ml', 'ചോദിക്കൂ, തേടൂ, മുട്ടൂ', 'ചോദിക്കുന്നവന് ലഭിക്കും, തേടുന്നവൻ കണ്ടെത്തും എന്ന് യേശു പറഞ്ഞു. മുട്ടുന്നവന്റെ മുൻപിൽ വാതിൽ തുറക്കപ്പെടും. ദൈവം തന്റെ മക്കൾക്ക് നല്ലത് നൽകാൻ ആഗ്രഹിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440017', 'hi', 'संकरा फाटक', 'यीशु ने कहा कि स्वर्ग का रास्ता संकरा है और उसे थोड़े ही लोग पाते हैं। चौड़ा और आसान रास्ता विनाश की ओर ले जाता है। हमें सच्चाई के संकरे रास्ते पर चलने का चुनाव करना है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440017', 'ml', 'ഇടുങ്ങിയ വഴി', 'സ്വർഗ്ഗത്തിലേക്കുള്ള വഴി ഇടുങ്ങിയതാണ്, കുറച്ചുപേർ മാത്രമേ അത് കണ്ടെത്തൂ എന്ന് യേശു പറഞ്ഞു. വിശാലവും എളുപ്പവുമായ വഴി നാശത്തിലേക്ക് നയിക്കുന്നു. സത്യത്തിന്റെ ഇടുങ്ങിയ വഴിയിൽ നടക്കാൻ നാം തിരഞ്ഞെടുക്കണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440018', 'hi', 'वृक्ष और उसके फल', 'यीशु ने सिखाया कि अच्छे पेड़ से अच्छे फल मिलते हैं और बुरे से बुरे। हम लोगों को उनके फलों से पहचान सकते हैं। एक मसीही के जीवन में परमेश्वर का प्रेम, शांति और भलाई दिखनी चाहिए।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440018', 'ml', 'മരവും അതിന്റെ ഫലവും', 'നല്ല മരം നല്ല ഫലം കൊടുക്കും, ചീത്ത മരം ചീത്ത ഫലം കൊടുക്കും എന്ന് യേശു പഠിപ്പിച്ചു. ഫലങ്ങളിൽ നിന്ന് ആളുകളെ തിരിച്ചറിയാം. ഒരു ക്രിസ്ത്യാനിയുടെ ജീവിതത്തിൽ ദൈവ സ്നേഹവും സമാധാനവും നന്മയും കാണപ്പെടണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440019', 'hi', 'सच्चे और झूठे शिष्य', 'हर कोई जो प्रभु प्रभु कहता है, स्वर्ग के राज्य में नहीं जाएगा। यीशु उन्हें जानना चाहता है जो सच में परमेश्वर की इच्छा पूरी करते हैं। विश्वास केवल शब्दों में नहीं, बल्कि जीवन में दिखना चाहिए।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440019', 'ml', 'യഥാർഥ ശിഷ്യന്മാർ', 'കർത്താവേ കർത്താവേ എന്ന് പറയുന്ന എല്ലാവരും സ്വർഗ്ഗ രാജ്യത്തിൽ കടക്കില്ല. ദൈവ ഇഷ്ടം ചെയ്യുന്നവരെ യേശു യഥാർഥ ശിഷ്യരായി അംഗീകരിക്കുന്നു. വിശ്വാസം വെറും വാക്കുകളിൽ മാത്രമല്ല, ജീവിതത്തിലും പ്രകടമാകണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab200000-e29b-41d4-a716-446655440020', 'hi', 'बुद्धिमान और मूर्ख निर्माता', 'यीशु के वचनों को सुनकर पालन करने वाला बुद्धिमान निर्माता जैसा है। जो केवल सुनता है पर पालन नहीं करता, वह बालू पर घर बनाने वाले जैसा है। जीवन की नींव परमेश्वर के वचन पर बनाना जरूरी है।', 'विश्वास की नींव'),
  ('ab200000-e29b-41d4-a716-446655440020', 'ml', 'ജ്ഞാനിയും മൂഢനും', 'യേശുവിന്റെ വചനം കേട്ട് പ്രവർത്തിക്കുന്നവൻ പാറമേൽ വീടുപണിതവനെ പോലെ ജ്ഞാനിയാണ്. കേൾക്കുക മാത്രം ചെയ്ത് അനുസരിക്കാത്തവൻ മണലിൽ വീടുപണിതവനെ പോലെ മൂഢനാണ്. ജീവിതത്തിന്റെ അടിത്തറ ദൈവ വചനത്തിൽ പണിയണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ')
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES
  ('ab300000-e29b-41d4-a716-446655440001', 'hi', 'सुसमाचार की शक्ति और मानव का पाप', 'परमेश्वर का सुसमाचार हर विश्वास करने वाले के लिए उद्धार की शक्ति है। पौलुस बताता है कि सभी मनुष्य पाप में हैं और परमेश्वर के न्याय के अधीन हैं। इसलिए हम सभी को उसके अनुग्रह की जरूरत है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440001', 'ml', 'സുവിശേഷത്തിന്റെ ശക്തിയും മനുഷ്യന്റെ പാപവും', 'ദൈവത്തിന്റെ സുവിശേഷം വിശ്വസിക്കുന്ന എല്ലാവർക്കും രക്ഷ നൽകുന്ന ശക്തിയാണ്. എല്ലാ മനുഷ്യരും പാപത്തിൽ ആണെന്നും ദൈവത്തിന്റെ ന്യായവിധിക്ക് അധീനരാണെന്നും പൗലോസ് വ്യക്തമാക്കുന്നു. അതുകൊണ്ട് നമുക്ക് എല്ലാവർക്കും ദൈവത്തിന്റെ കൃപ ആവശ്യമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440002', 'hi', 'परमेश्वर का निष्पक्ष न्याय', 'परमेश्वर सभी लोगों का न्याय उनके कामों के अनुसार करता है। वह किसी के साथ पक्षपात नहीं करता — न यहूदी, न अन्यजाति। हर इंसान को एक दिन उसके सामने खड़ा होना है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440002', 'ml', 'ദൈവത്തിന്റെ നീതിയുള്ള വിധി', 'ദൈവം എല്ലാ മനുഷ്യരെയും അവരുടെ പ്രവൃത്തികൾക്ക് അനുസരിച്ച് വിധിക്കുന്നു. അവൻ ആരെയും പക്ഷഭേദം കൂടാതെ നോക്കുന്നു — യഹൂദനോ ജാതിക്കാരനോ ആകട്ടെ. ഒരു ദിവസം നാം ഓരോരുത്തരും അവന്റെ മുൻപിൽ നിൽക്കേണ്ടിവരും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440003', 'hi', 'विश्वास द्वारा धार्मिकता', 'कोई भी इंसान अपने अच्छे कामों से परमेश्वर के सामने धर्मी नहीं ठहर सकता। परमेश्वर यीशु मसीह पर विश्वास करने से हमें धर्मी घोषित करता है। यह उसका मुफ्त उपहार है जो हर विश्वास करने वाले को मिलता है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440003', 'ml', 'വിശ്വാസത്തിലൂടെ നീതി', 'ഒരു മനുഷ്യനും സ്വന്തം നല്ല പ്രവൃത്തികൾ കൊണ്ട് ദൈവത്തിന്റെ മുൻപിൽ നീതിമാനാകാൻ കഴിയില്ല. യേശുക്രിസ്തുവിൽ വിശ്വസിക്കുന്നതിലൂടെ ദൈവം നമ്മെ നീതിമാൻ എന്ന് പ്രഖ്യാപിക്കുന്നു. ഇത് വിശ്വസിക്കുന്ന എല്ലാവർക്കും ലഭിക്കുന്ന ദൈവത്തിന്റെ സൗജന്യ സമ്മാനമാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440004', 'hi', 'अब्राहम — विश्वास का पिता', 'अब्राहम ने परमेश्वर पर भरोसा किया और परमेश्वर ने उसे धर्मी गिना। उसकी धार्मिकता कामों से नहीं, बल्कि विश्वास से आई। हम भी उसी तरह विश्वास के द्वारा परमेश्वर के परिवार में शामिल हो सकते हैं।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440004', 'ml', 'അബ്രഹാം — വിശ്വാസത്തിന്റെ പിതാവ്', 'അബ്രഹാം ദൈവത്തിൽ വിശ്വസിച്ചു, ദൈവം അവനെ നീതിമാൻ എന്ന് കണക്കാക്കി. അവന്റെ നീതി പ്രവൃത്തികളിൽ നിന്നല്ല, വിശ്വാസത്തിൽ നിന്ന് വന്നു. നമുക്കും അതേ വിശ്വാസത്തിലൂടെ ദൈവത്തിന്റെ കുടുംബത്തിൽ ഉൾപ്പെടാൻ കഴിയും.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440005', 'hi', 'मसीह के द्वारा परमेश्वर के साथ शांति', 'यीशु मसीह के द्वारा हमारा परमेश्वर के साथ मेल हो गया है। अब हमें परमेश्वर के क्रोध का डर नहीं, बल्कि उसके प्रेम में खड़े रहने की खुशी है। यह शांति हमें हर कठिनाई में भी स्थिर रखती है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440005', 'ml', 'ക്രിസ്തുവിലൂടെ ദൈവവുമായി സമാധാനം', 'യേശുക്രിസ്തുവിലൂടെ നമ്മൾ ദൈവവുമായി അനുരഞ്ജിതരായി. ഇനി ദൈവത്തിന്റെ കോപത്തെ ഭയക്കേണ്ടതില്ല, പകരം അവന്റെ സ്നേഹത്തിൽ നിലകൊള്ളാം. ഈ സമാധാനം ഏത് ബുദ്ധിമുട്ടിലും നമ്മെ ഉറച്ചു നിർത്തുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440006', 'hi', 'पाप के प्रति मरे, मसीह में जीवित', 'जब हम यीशु में विश्वास करते हैं तो हम उसके साथ पाप के प्रति मर जाते हैं। अब हम पाप के दास नहीं हैं बल्कि परमेश्वर के लिए जीते हैं। यह नया जीवन हमें हर दिन पाप से दूर और परमेश्वर के करीब चलने की ताकत देता है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440006', 'ml', 'പാപത്തോട് മരിച്ചവർ, ക്രിസ്തുവിൽ ജീവിക്കുന്നവർ', 'നാം യേശുവിൽ വിശ്വസിക്കുമ്പോൾ പാപത്തോട് അവനോടൊപ്പം മരിക്കുന്നു. ഇനി നാം പാപത്തിന്റെ അടിമകളല്ല, ദൈവത്തിനുവേണ്ടി ജീവിക്കുന്നവരാണ്. ഈ പുതിയ ജീവിതം നമ്മെ ദൈവത്തോട് അടുത്ത് നടക്കാൻ ശക്തി നൽകുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440007', 'hi', 'पाप और व्यवस्था से संघर्ष', 'पौलुस बताता है कि व्यवस्था अच्छी है, लेकिन वह हमें पाप से बचाने में असमर्थ है। हम भीतर से अच्छा करना चाहते हैं पर पाप हमें खींचता है। यीशु मसीह ही इस संघर्ष से हमें छुड़ाने वाला है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440007', 'ml', 'പാപവും ന്യായപ്രമാണവുമായുള്ള പോരാട്ടം', 'ന്യായപ്രമാണം നല്ലതാണ്, പക്ഷേ അത് നമ്മെ പാപത്തിൽ നിന്ന് രക്ഷിക്കാൻ ശക്തിയില്ലാത്തതാണെന്ന് പൗലോസ് വ്യക്തമാക്കുന്നു. നല്ലത് ചെയ്യണമെന്ന് ആഗ്രഹിക്കുമ്പോഴും പാപം നമ്മെ വലിക്കുന്നു. യേശുക്രിസ്തു മാത്രമേ ഈ പോരാട്ടത്തിൽ നിന്ന് നമ്മെ വിടുവിക്കൂ.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440008', 'hi', 'आत्मा में जीवन', 'पवित्र आत्मा हमारे भीतर रहता है और हमें परमेश्वर की संतान का भरोसा देता है। वह हमें प्रार्थना में सहायता करता है और हमें सत्य की राह पर चलाता है। इस संसार की कोई भी तकलीफ हमें परमेश्वर के प्रेम से अलग नहीं कर सकती।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440008', 'ml', 'ആത്മാവിലുള്ള ജീവിതം', 'പരിശുദ്ധാത്മാവ് നമ്മിൽ വസിക്കുകയും നാം ദൈവത്തിന്റെ മക്കൾ എന്ന ഉറപ്പ് നൽകുകയും ചെയ്യുന്നു. അവൻ പ്രാർത്ഥനയിൽ നമ്മെ സഹായിക്കുകയും സത്യത്തിന്റെ വഴിയിൽ നടത്തുകയും ചെയ്യുന്നു. ഈ ലോകത്തിലെ ഒരു ബുദ്ധിമുട്ടിനും ദൈവത്തിന്റെ സ്നേഹത്തിൽ നിന്ന് നമ്മെ വേർപെടുത്താൻ കഴിയില്ല.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440009', 'hi', 'परमेश्वर की संप्रभु चुनाव', 'परमेश्वर अपनी इच्छा और उद्देश्य के अनुसार लोगों को चुनता है। यह उसकी दया और संप्रभुता को दर्शाता है। उसके निर्णय हमेशा सही और न्यायपूर्ण होते हैं, भले ही हम उन्हें पूरी तरह समझ न सकें।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440009', 'ml', 'ദൈവത്തിന്റെ പരമാധികാര തിരഞ്ഞെടുപ്പ്', 'ദൈവം തന്റെ ഇഷ്ടവും ഉദ്ദേശ്യവും അനുസരിച്ച് ആളുകളെ തിരഞ്ഞെടുക്കുന്നു. ഇത് അവന്റെ കരുണയും പരമാധികാരവും വെളിപ്പെടുത്തുന്നു. അവന്റെ തീരുമാനങ്ങൾ നാം പൂർണമായി മനസ്സിലാക്കില്ലെങ്കിലും എല്ലാം ശരിയും നീതിയുമുള്ളവയാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440010', 'hi', 'बुलाने वाले सभी के लिए उद्धार', 'कोई भी व्यक्ति प्रभु यीशु के नाम को पुकारे तो वह बच जाएगा। उद्धार सिर्फ एक जाति या समूह के लिए नहीं, बल्कि सभी के लिए है। इसीलिए सुसमाचार को सभी तक पहुंचाना जरूरी है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440010', 'ml', 'വിളിക്കുന്ന എല്ലാവർക്കും രക്ഷ', 'കർത്താവായ യേശുവിന്റെ നാമം വിളിക്കുന്ന ഏവനും രക്ഷിക്കപ്പെടും. രക്ഷ ഒരു വംശത്തിനോ കൂട്ടത്തിനോ മാത്രമല്ല, എല്ലാവർക്കും ഉള്ളതാണ്. അതുകൊണ്ടാണ് സുവിശേഷം എല്ലാവരിലും എത്തിക്കേണ്ടത് അത്യാവശ്യമായിരിക്കുന്നത്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440011', 'hi', 'इस्राएल के भविष्य का रहस्य', 'परमेश्वर ने इस्राएल को अस्वीकार नहीं किया है, बल्कि उसका एक बड़ा उद्देश्य है। अन्यजातियों के आने के बाद एक दिन इस्राएल भी परमेश्वर की ओर लौटेगा। परमेश्वर की योजना सबके लिए दया और उद्धार की है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440011', 'ml', 'ഇസ്രായേലിന്റെ ഭാവിയുടെ രഹസ്യം', 'ദൈവം ഇസ്രായേലിനെ തള്ളിക്കളഞ്ഞിട്ടില്ല, അവന് വലിയ ഒരു ഉദ്ദേശ്യം ഉണ്ട്. ജാതികൾ വരുന്നതിനു ശേഷം ഒരു ദിവസം ഇസ്രായേലും ദൈവത്തിലേക്ക് തിരിയും. ദൈവത്തിന്റെ പദ്ധതി എല്ലാവർക്കും കരുണയും രക്ഷയും നൽകുന്നതാണ്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440012', 'hi', 'जीवित बलिदान — परमेश्वर की सेवा', 'पौलुस हमसे विनती करता है कि हम अपने शरीर को परमेश्वर के लिए जीवित बलिदान के रूप में समर्पित करें। इस संसार के साथ नहीं, बल्कि परमेश्वर की इच्छा के अनुसार जीएं। अपने दिए गए वरदानों से एक दूसरे की सेवा करें।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440012', 'ml', 'ജീവനുള്ള ബലി — ദൈവത്തിനുള്ള സേവനം', 'നമ്മുടെ ശരീരത്തെ ദൈവത്തിനുള്ള ജീവനുള്ള ബലിയായി സമർപ്പിക്കാൻ പൗലോസ് അഭ്യർത്ഥിക്കുന്നു. ഈ ലോകത്തിന്റെ രീതിക്കനുസരിച്ചല്ല, ദൈവത്തിന്റെ ഇഷ്ടത്തിനനുസരിച്ച് ജീവിക്കണം. ദൈവം നൽകിയ വരദാനം കൊണ്ട് പരസ്പരം സേവിക്കണം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440013', 'hi', 'अधिकारियों का आदर और प्रेम का ऋण', 'परमेश्वर ने शासन अधिकारियों को स्थापित किया है इसलिए हमें उनका आदर करना चाहिए। हम पर किसी का कोई ऋण न हो, सिवाय एक दूसरे से प्रेम करने के। प्रेम ही सारी व्यवस्था को पूरा करता है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440013', 'ml', 'അധികാരികളോടുള്ള ബഹുമാനവും സ്നേഹത്തിന്റെ കടവും', 'ദൈവം ഭരണ അധികാരികളെ നിശ്ചയിച്ചിരിക്കുന്നതിനാൽ നാം അവരെ ബഹുമാനിക്കണം. പരസ്പരം സ്നേഹിക്കുക എന്നതൊഴികെ ആർക്കും ഒരു കടവും ഉണ്ടായിരിക്കരുത്. സ്നേഹമാണ് ന്യായപ്രമാണം മുഴുവൻ നിറവേറ്റുന്നത്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440014', 'hi', 'एक दूसरे को स्वीकार करना', 'विश्वास में कमजोर और मजबूत दोनों को एक दूसरे को स्वीकार करना चाहिए। छोटे-छोटे मुद्दों पर आपस में झगड़ना ठीक नहीं। हम सब परमेश्वर के सामने जवाबदेह हैं, इसलिए दूसरों पर दोष नहीं लगाना चाहिए।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440014', 'ml', 'പരസ്പരം സ്വീകരിക്കൽ', 'വിശ്വാസത്തിൽ ദുർബലരും ശക്തരും പരസ്പരം സ്വീകരിക്കണം. ചെറിയ കാര്യങ്ങളിൽ തർക്കിക്കുന്നത് ശരിയല്ല. നാം എല്ലാവരും ദൈവത്തിന്റെ മുൻപിൽ ഉത്തരം പറയേണ്ടവരാണ്, അതുകൊണ്ട് മറ്റുള്ളവരെ കുറ്റം പറയരുത്.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440015', 'hi', 'मसीह के मिशन में एकजुट', 'यीशु ने यहूदियों और अन्यजातियों दोनों को एक साथ स्वीकार किया। हम भी एक दूसरे को स्वीकार करके परमेश्वर की महिमा करें। मिलकर सुसमाचार फैलाना ही हमारी साझा जिम्मेदारी है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440015', 'ml', 'ക്രിസ്തുവിന്റെ ദൗത്യത്തിൽ ഒന്നിച്ച്', 'യേശു യഹൂദരെയും ജാതിക്കാരെയും ഒരുമിച്ച് സ്വീകരിച്ചു. നാമും പരസ്പരം സ്വീകരിച്ച് ദൈവത്തെ മഹത്വപ്പെടുത്തണം. സുവിശേഷം ഒരുമിച്ച് പ്രചരിപ്പിക്കുക എന്നതാണ് നമ്മുടെ പൊതുവായ ഉത്തരവാദിത്തം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab300000-e29b-41d4-a716-446655440016', 'hi', 'अभिवादन और विश्वास का समुदाय', 'पौलुस कलीसिया के कई सदस्यों को नाम लेकर प्रणाम करता है। इससे पता चलता है कि कलीसिया एक परिवार है जहाँ हर व्यक्ति मायने रखता है। एक दूसरे का आदर करना और साथ में मिलकर चलना ही विश्वास का असली रूप है।', 'विश्वास की नींव'),
  ('ab300000-e29b-41d4-a716-446655440016', 'ml', 'അഭിവാദനങ്ങളും വിശ്വാസ സമൂഹവും', 'പൗലോസ് സഭയിലെ പല അംഗങ്ങളെ പേരെടുത്ത് അഭിവാദ്യം ചെയ്യുന്നു. സഭ ഒരു കുടുംബമാണ്, അവിടെ ഓരോ വ്യക്തിക്കും പ്രാധാന്യമുണ്ട് എന്ന് ഇത് കാണിക്കുന്നു. പരസ്പരം ബഹുമാനിക്കുകയും ഒരുമിച്ച് നടക്കുകയും ചെയ്യുന്നതാണ് വിശ്വാസത്തിന്റെ യഥാർത്ഥ രൂപം.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ')
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES
  ('ab400000-e29b-41d4-a716-446655440001', 'hi', 'अंतिम भोज', 'यीशु ने अपने शिष्यों के साथ अपना अंतिम भोज किया। उसने रोटी और दाखरस लेकर अपने बलिदान को याद करने का एक नया तरीका दिया। यह प्रेम का एक विशेष पल था जो हमें यीशु की मृत्यु की याद दिलाता है।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440001', 'ml', 'അന്ത്യ അത്താഴം', 'യേശു തന്റെ ശിഷ്യന്മാരോടൊപ്പം അവസാനത്തെ ഭക്ഷണം കഴിച്ചു. അവൻ അപ്പവും വീഞ്ഞും എടുത്ത് തന്റെ ബലിയെ ഓർക്കാനുള്ള ഒരു പുതിയ വഴി നൽകി. ഇത് സ്നേഹത്തിന്റെ ഒരു പ്രത്യേക നിമിഷമായിരുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440002', 'hi', 'गतसमनी का बाग', 'यीशु अपने शिष्यों को लेकर गतसमनी के बाग में गया और प्रार्थना करने लगा। वह जानता था कि क्रूस पर कठिन समय आने वाला है, फिर भी उसने परमेश्वर की इच्छा को अपनाया। यह हमें सिखाता है कि कठिन समय में भी परमेश्वर से बात करनी चाहिए।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440002', 'ml', 'ഗെത്സെമനി തോട്ടം', 'യേശു ശിഷ്യന്മാരെ കൂട്ടി ഗെത്സെമനി തോട്ടത്തിൽ പോയി പ്രാർഥിച്ചു. ക്രൂശിൽ കഷ്ടം വരാൻ പോകുന്നത് അവൻ അറിഞ്ഞിട്ടും ദൈവത്തിന്റെ ഇഷ്ടം സ്വീകരിച്ചു. കഷ്ടകാലത്തും ദൈവത്തോട് സംസാരിക്കണം എന്ന് ഇത് നമ്മെ പഠിപ്പിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440003', 'hi', 'विश्वासघात और गिरफ्तारी', 'यहूदा ने पैसों के लालच में यीशु को धोखा दिया और सैनिकों को उसके पास ले आया। यीशु को गिरफ्तार किया गया, फिर भी वह शांत रहा। इसमें हम देखते हैं कि यीशु जानबूझकर हमारे लिए यह सब सहने को तैयार था।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440003', 'ml', 'ഒറ്റുകൊടുക്കലും അറസ്റ്റും', 'യൂദാസ് പണത്തിന്റെ ആഗ്രഹത്തിൽ യേശുവിനെ ഒറ്റുകൊടുത്ത് പടയാളികളെ അവിടേക്ക് കൊണ്ടുവന്നു. യേശുവിനെ അറസ്റ്റ് ചെയ്തെങ്കിലും അവൻ ശാന്തനായി നിന്നു. നമുക്കുവേണ്ടി ഇതെല്ലാം സഹിക്കാൻ അവൻ മനഃപൂർവം തയ്യാറായിരുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440004', 'hi', 'पतरस का इनकार', 'पतरस ने तीन बार यीशु को न जानने का दावा किया। जब मुर्गे ने बांग दी, तब पतरस को यीशु की बात याद आई और वह फूट-फूटकर रोया। यह हमें दिखाता है कि गलतियों के बाद भी पश्चाताप करके परमेश्वर के पास लौट सकते हैं।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440004', 'ml', 'പത്രോസിന്റെ തള്ളിപ്പറയൽ', 'പത്രോസ് മൂന്ന് തവണ യേശുവിനെ അറിയില്ല എന്ന് പറഞ്ഞു. കോഴി കൂവിയപ്പോൾ യേശുവിന്റെ വാക്ക് ഓർമ വന്ന് പത്രോസ് കരഞ്ഞു. തെറ്റുകൾക്കു ശേഷവും അനുതപിച്ച് ദൈവത്തിലേക്ക് മടങ്ങാം എന്ന് ഇത് കാണിക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440005', 'hi', 'महासभा के सामने यीशु', 'यीशु को यहूदी नेताओं के सामने लाया गया जो उसे दोषी ठहराना चाहते थे। यीशु ने सच बोला कि वह परमेश्वर का पुत्र है। नेताओं ने इसे ईशनिंदा माना और उसे मृत्युदंड देने का फैसला किया।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440005', 'ml', 'മഹാപുരോഹിതന്മാരുടെ മുമ്പിൽ യേശു', 'യേശുവിനെ യഹൂദ നേതാക്കന്മാരുടെ മുന്നിൽ കൊണ്ടുവന്നു, അവർ അവനെ കുറ്റക്കാരനാക്കാൻ ആഗ്രഹിച്ചു. താൻ ദൈവപുത്രൻ എന്ന് യേശു സത്യം പറഞ്ഞു. നേതാക്കന്മാർ ഇത് ദൈവദൂഷണം ആണെന്ന് കരുതി അവനെ വധശിക്ഷയ്ക്ക് വിധിക്കാൻ തീരുമാനിച്ചു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440006', 'hi', 'पिलातुस के सामने यीशु', 'यीशु को रोमी गवर्नर पिलातुस के सामने पेश किया गया। पिलातुस को यीशु में कोई दोष नहीं मिला, लेकिन भीड़ के दबाव में उसने यीशु को क्रूस पर चढ़ाने का आदेश दे दिया। यह हमें बताता है कि यीशु निर्दोष था पर हमारे लिए दंड उठाया।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440006', 'ml', 'പീലാത്തോസിന്റെ മുമ്പിൽ യേശു', 'യേശുവിനെ റോമൻ ഗവർണർ പീലാത്തോസിന്റെ മുന്നിൽ കൊണ്ടുവന്നു. പീലാത്തോസിന് യേശുവിൽ കുറ്റം കണ്ടില്ല, എങ്കിലും ജനക്കൂട്ടത്തിന്റെ സമ്മർദ്ദത്തിൽ അവനെ ക്രൂശിക്കാൻ ആജ്ഞ നൽകി. യേശു നിർദോഷിയായിരുന്നെങ്കിലും നമുക്കുവേണ്ടി ശിക്ഷ ഏറ്റുകൊണ്ടു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440007', 'hi', 'क्रूस पर चढ़ाया जाना', 'यीशु को गोलगोथा ले जाया गया जहाँ उसे क्रूस पर ठोंक दिया गया। उसने क्रूस पर भी दूसरों के लिए प्रार्थना की और उन्हें क्षमा माँगी। यह हमारे पापों की माफी के लिए उसका सबसे बड़ा बलिदान था।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440007', 'ml', 'ക്രൂശീകരണം', 'യേശുവിനെ ഗൊൽഗൊഥയിലേക്ക് കൊണ്ടുപോയി ക്രൂശിൽ തറച്ചു. ക്രൂശിലും അവൻ മറ്റുള്ളവർക്കുവേണ്ടി പ്രാർഥിച്ച് ക്ഷമ ചോദിച്ചു. ഇത് നമ്മുടെ പാപങ്ങളുടെ മോചനത്തിനുവേണ്ടിയുള്ള അവന്റെ ഏറ്റവും വലിയ ബലിയായിരുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440008', 'hi', 'यीशु की मृत्यु', 'क्रूस पर घंटों के कष्ट के बाद यीशु ने अपनी आत्मा परमेश्वर को सौंप दी। उस समय मंदिर का परदा ऊपर से नीचे तक फट गया। इसका मतलब है कि यीशु की मृत्यु से हमारे और परमेश्वर के बीच का रास्ता खुल गया।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440008', 'ml', 'യേശുവിന്റെ മരണം', 'ക്രൂശിൽ മണിക്കൂറുകൾ കഷ്ടം അനുഭവിച്ച ശേഷം യേശു തന്റെ ആത്മാവ് ദൈവത്തിൽ ഏൽപ്പിച്ചു. ആ സമയം ദേവാലയത്തിലെ തിരശ്ശീല മുകളിൽ നിന്ന് താഴേക്ക് കീറി. ഇതിന്റെ അർഥം, യേശുവിന്റെ മരണത്തിലൂടെ നമ്മുക്കും ദൈവത്തിനും ഇടയിലുള്ള വഴി തുറന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440009', 'hi', 'यीशु का दफनाया जाना', 'अरिमतिया के यूसुफ ने यीशु के शरीर को लेकर एक नई कब्र में रखा। उसके शिष्य दुखी थे और उन्हें लगा कि सब कुछ खत्म हो गया। पर यह खत्म नहीं था — यह परमेश्वर की बड़ी योजना का एक हिस्सा था।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440009', 'ml', 'യേശുവിന്റെ അടക്കം', 'അരിമത്ഥ്യയിലെ യോസേഫ് യേശുവിന്റെ ശരീരം എടുത്ത് ഒരു പുതിയ കല്ലറയിൽ വെച്ചു. ശിഷ്യന്മാർ ദുഃഖിതരായി, എല്ലാം തീർന്നു എന്ന് അവർ കരുതി. എന്നാൽ ഇത് അവസാനമായിരുന്നില്ല — ദൈവത്തിന്റെ വലിയ പദ്ധതിയുടെ ഒരു ഭാഗം മാത്രമായിരുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440010', 'hi', 'खाली कब्र', 'तीसरे दिन सुबह जब स्त्रियाँ कब्र पर पहुँचीं तो उन्होंने पत्थर हटा हुआ और कब्र खाली पाई। एक स्वर्गदूत ने कहा कि यीशु जी उठा है। यह सबसे बड़ी खुशखबरी थी — यीशु मृत्यु पर जीत गया!', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440010', 'ml', 'ശൂന്യമായ കല്ലറ', 'മൂന്നാം ദിവസം രാവിലെ സ്ത്രീകൾ കല്ലറയിൽ എത്തിയപ്പോൾ കല്ല് നീക്കിയിരിക്കുന്നതും കല്ലറ ശൂന്യവും കണ്ടു. ഒരു ദൂതൻ യേശു ഉയിർത്തെഴുന്നേറ്റു എന്ന് അറിയിച്ചു. ഇത് ഏറ്റവും വലിയ സന്തോഷ വാർത്തയായിരുന്നു — യേശു മരണത്തെ ജയിച്ചു!', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440011', 'hi', 'यीशु का मरियम मगदलीनी को दर्शन', 'मरियम मगदलीनी खाली कब्र के पास रो रही थी। यीशु ने उसे उसका नाम लेकर बुलाया और वह पहचान गई। यीशु ने उसे जाकर शिष्यों को यह खुशखबरी देने के लिए कहा कि वह जी उठा है।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440011', 'ml', 'മറിയ മഗ്ദലേനക്ക് യേശു പ്രത്യക്ഷപ്പെടൽ', 'മറിയ മഗ്ദലേന ശൂന്യ കല്ലറയ്ക്ക് അടുത്ത് കരഞ്ഞുകൊണ്ട് നിന്നു. യേശു അവളുടെ പേര് വിളിച്ചപ്പോൾ അവൾ തിരിച്ചറിഞ്ഞു. ശിഷ്യന്മാരോട് ഈ സന്തോഷ വാർത്ത അറിയിക്കാൻ അവൻ അവളോട് ആവശ്യപ്പെട്ടു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440012', 'hi', 'एम्माऊस की राह पर', 'दो शिष्य उदास होकर एम्माऊस जा रहे थे जब यीशु उनके साथ चलने लगा पर वे पहचान नहीं पाए। यीशु ने उन्हें शास्त्र से समझाया और रोटी तोड़ते समय उनकी आँखें खुलीं। यह दिखाता है कि यीशु हर यात्रा में हमारे साथ चलता है।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440012', 'ml', 'എമ്മാവൂസ് വഴിയിൽ', 'രണ്ട് ശിഷ്യന്മാർ വിഷണ്ണരായി എമ്മാവൂസിലേക്ക് പോകുമ്പോൾ യേശു അവരോടൊപ്പം നടന്നു, പക്ഷേ അവർ തിരിച്ചറിഞ്ഞില്ല. യേശു വേദഗ്രന്ഥം വ്യാഖ്യാനിച്ചു, അപ്പം നുറുക്കിയപ്പോൾ അവരുടെ കണ്ണ് തുറന്നു. ഓരോ യാത്രയിലും യേശു നമ്മോടൊപ്പം നടക്കുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440013', 'hi', 'शिष्यों को यीशु का दर्शन', 'यीशु बंद कमरे में अपने शिष्यों के पास आया और कहा "तुम्हें शांति मिले।" उसने उन्हें अपने हाथ और पाँव दिखाए जिससे वे जान सकें कि यह वही यीशु है। उनका डर खुशी में बदल गया।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440013', 'ml', 'ശിഷ്യന്മാർക്ക് യേശു പ്രത്യക്ഷപ്പെടൽ', 'യേശു അടഞ്ഞ മുറിയിൽ ശിഷ്യന്മാരുടെ അടുക്കൽ വന്ന് "നിങ്ങൾക്ക് സമാധാനം" എന്ന് പറഞ്ഞു. ഇത് ആ യേശു തന്നെ എന്ന് അറിയാൻ കൈകളും കാലുകളും കാണിച്ചു. അവരുടെ ഭയം സന്തോഷമായി മാറി.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440014', 'hi', 'थोमा: संदेह और विश्वास', 'थोमा ने कहा कि जब तक वह यीशु के घाव न देखे और न छुए, तब तक विश्वास नहीं करेगा। यीशु ने आकर थोमा को अपने घाव दिखाए। थोमा ने कहा "मेरे प्रभु और मेरे परमेश्वर!" — यह उसकी गहरी पहचान थी।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440014', 'ml', 'തോമാ: സംശയവും വിശ്വാസവും', 'തോമാ പറഞ്ഞു, യേശുവിന്റെ മുറിവ് കണ്ട് തൊടാതെ വിശ്വസിക്കില്ല എന്ന്. യേശു വന്ന് തോമാക്ക് മുറിവ് കാണിച്ചു. "എന്റെ കർത്താവും എന്റെ ദൈവവും!" എന്ന് തോമാ പറഞ്ഞു — ഇത് അവന്റെ ആഴമായ തിരിച്ചറിവായിരുന്നു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440015', 'hi', 'महान आदेश', 'यीशु ने अपने शिष्यों को सभी जातियों में जाकर सुसमाचार सुनाने और लोगों को चेला बनाने का आदेश दिया। उसने कहा कि स्वर्ग और पृथ्वी का सारा अधिकार उसे दिया गया है। उसने वादा किया कि वह हमेशा हमारे साथ रहेगा।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440015', 'ml', 'മഹത്തായ കല്പന', 'എല്ലാ ജനതകളിലേക്കും പോയി സുവിശേഷം പ്രസംഗിക്കാനും ശിഷ്യന്മാരെ ഉണ്ടാക്കാനും യേശു ആജ്ഞ നൽകി. സ്വർഗ്ഗത്തിലും ഭൂമിയിലും ഉള്ള സർവ അധികാരവും തനിക്ക് നൽകിയിരിക്കുന്നു എന്ന് അവൻ പറഞ്ഞു. എന്നും നമ്മോടൊപ്പം ഉണ്ടാകും എന്ന് വാഗ്ദാനം ചെയ്തു.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ'),
  ('ab400000-e29b-41d4-a716-446655440016', 'hi', 'स्वर्गारोहण', 'यीशु अपने शिष्यों को आशीष देते हुए स्वर्ग में उठा लिया गया। एक बादल ने उसे उनकी दृष्टि से ओझल कर दिया। स्वर्गदूतों ने कहा कि जैसे वह गया, वैसे ही वह फिर आएगा — यह हमारी आशा है।', 'विश्वास की नींव'),
  ('ab400000-e29b-41d4-a716-446655440016', 'ml', 'സ്വർഗ്ഗാരോഹണം', 'യേശു ശിഷ്യന്മാരെ അനുഗ്രഹിച്ചുകൊണ്ട് സ്വർഗ്ഗത്തിലേക്ക് എടുക്കപ്പെട്ടു. ഒരു മേഘം അവനെ അവരുടെ കാഴ്ചയിൽ നിന്ന് മറച്ചു. അവൻ പോയതുപോലെ തന്നെ തിരിച്ചുവരും എന്ന് ദൂതന്മാർ പറഞ്ഞു — ഇതാണ് നമ്മുടെ പ്രത്യാശ.', 'വിശ്വാസത്തിന്റെ അടിത്തറകൾ')
